SELECT pitch_type, pitch_speed, pitch_result, pitch_location_y
FROM pitching_data
WHERE stand = 'R' AND runner = 0 AND strikes < 2;

SELECT pitch_speed
FROM pitching_data
WHERE pitch_id = 0;

SELECT accuracy
FROM umpire_calls
WHERE call_type = 'Strike';

SELECT pitch_name
FROM pitch_types
WHERE pitch_accuracy = (SELECT MAX(pitch_accuracy) FROM pitch_types);

SELECT SUM(pitches_thrown) AS total_pitches_thrown
FROM pitcher_game_mapping
WHERE pitcher_id = 0 AND game_id = 0;

SELECT COUNT(DISTINCT pitch_type) AS distinct_pitch_types
FROM pitching_data
WHERE pitcher_id = 0 AND game_id = 0;

SELECT pitch_speed
FROM pitching_data
WHERE pitch_speed > (SELECT AVG(pitch_speed) FROM pitching_data);
